def main() -> None:
    import numpy as np

    model = BatchInferenceModel()
    batch_size = 16
    total_batches = 8
    total_samples = batch_size * total_batches

    inputs = np.random.randn(total_samples, 128).astype("float32")
    batches = [
        inputs[i : i + batch_size].tolist()
        for i in range(0, total_samples, batch_size)
    ]

    predictions = list(model.infer_batch.map(batches))
